import numpy as np

class Neuron:
    def __init__(self, n_features: int, activation: str = 'relu'):
        self.w = np.zeros(n_features)
        self.b = 0.0
        self.activation = activation
        valid = {'relu', 'sigmoid', 'tanh', 'linear'}
        if activation not in valid:
            raise ValueError(f"Unknown activation '{activation}'. Choose from {valid}")

    def activate(self, z: np.ndarray) -> np.ndarray:
        if self.activation == 'relu':
            return np.maximum(0, z)
        elif self.activation == 'sigmoid':
            z_clipped = np.clip(z, -500, 500)
            return 1 / (1 + np.exp(-z_clipped))
        elif self.activation == 'tanh':
            return np.tanh(z)
        else:  # linear
            return z

    def forward(self, x: np.ndarray) -> float:
        z = np.dot(self.w, x) + self.b
        return float(self.activate(np.array([z]))[0])

    def forward_batch(self, X: np.ndarray) -> np.ndarray:
        z = X @ self.w + self.b   # (N,)
        return self.activate(z)

